#!/usr/bin/env python3
"""Real Two URL Smoke bridge skeleton.

- Reads TOKEN_VK_APP or VIKTOR_TOKEN from the environment
- Calls URL 1 DataView method `view_turbine_data`
- Builds URL 2 payload from URL 2 saved/default values
- Maps candidate load fields into URL 2 mast inputs
- Preserves downstream geometry/geotech defaults or saved values
- Detects missing `step_analysis.esa_file` and logs BLOCKED instead of failing

TODO: The exact schema returned by URL 1 `view_turbine_data` is not proven by the
inspection summary. Candidate extraction logic below must be adapted once the raw
DataView payload structure is confirmed.
"""

from __future__ import annotations

import json
import os
import sys
from copy import deepcopy
from typing import Any, Dict, Iterable, Optional

import requests

API_BASE = "https://demo.viktor.ai/api"
SOURCE_WORKSPACE_ID = 2544
SOURCE_ENTITY_ID = 12039
TARGET_WORKSPACE_ID = 2515
TARGET_ENTITY_ID = 12040
SOURCE_METHOD = "view_turbine_data"

TARGET_BASE_PAYLOAD: Dict[str, Any] = {
    "step_geo": {
        "sec_mast": {
            "mast_diameter": 5,
            "mast_vertical_load": 4000,
            "mast_horizontal_load": 1500,
            "mast_moment": 150000,
        },
        "sec_slab": {
            "slab_diameter": 20,
            "slab_thickness": 3,
        },
        "sec_piles": {
            "num_piles": 30,
            "pile_length": 20,
            "pile_diameter": 500,
            "pile_edge_distance": 600,
        },
    },
    "step_geo_tech": {
        "sec_tip": {
            "tip_stiffness": 50000,
        },
        "sec_lateral": {
            "lateral_stiffness": 10000,
        },
    },
    "step_analysis": {
        "esa_file": None,
    },
}


def get_token() -> str:
    token = os.getenv("TOKEN_VK_APP") or os.getenv("VIKTOR_TOKEN")
    if not token:
        raise SystemExit("Missing TOKEN_VK_APP or VIKTOR_TOKEN")
    return token


def headers(token: str) -> Dict[str, str]:
    return {
        "Authorization": f"Bearer {token}",
        "Content-Type": "application/json",
        "Accept": "application/json",
    }


def deep_merge(base: Dict[str, Any], overlay: Dict[str, Any]) -> Dict[str, Any]:
    result = deepcopy(base)
    for key, value in overlay.items():
        if isinstance(value, dict) and isinstance(result.get(key), dict):
            result[key] = deep_merge(result[key], value)
        else:
            result[key] = deepcopy(value)
    return result


def get_entity_properties(token: str, workspace_id: int, entity_id: int) -> Dict[str, Any]:
    url = f"{API_BASE}/v1/workspaces/{workspace_id}/entities/{entity_id}"
    resp = requests.get(url, headers=headers(token), timeout=60)
    resp.raise_for_status()
    data = resp.json()
    return data.get("properties") or {}


def run_entity_method(token: str, workspace_id: int, entity_id: int, method_name: str) -> Dict[str, Any]:
    """Generic job runner skeleton.

    TODO: Confirm exact VIKTOR endpoint contract in your environment if needed.
    This implementation follows the common create-job then poll pattern.
    """
    create_url = f"{API_BASE}/v1/workspaces/{workspace_id}/entities/{entity_id}/jobs"
    payload = {
        "method": method_name,
        "params": None,
    }
    resp = requests.post(create_url, headers=headers(token), data=json.dumps(payload), timeout=60)
    resp.raise_for_status()
    job = resp.json()
    job_id = job.get("id")
    if not job_id:
        raise RuntimeError(f"No job id returned for method {method_name}: {job}")

    status_url = f"{API_BASE}/v1/workspaces/{workspace_id}/jobs/{job_id}"
    for _ in range(120):
        poll = requests.get(status_url, headers=headers(token), timeout=60)
        poll.raise_for_status()
        body = poll.json()
        status = (body.get("status") or "").lower()
        if status in {"success", "succeeded", "completed", "done"}:
            return body
        if status in {"failed", "error", "cancelled", "canceled"}:
            raise RuntimeError(f"Method {method_name} failed: {json.dumps(body, indent=2)}")
    raise TimeoutError(f"Timed out waiting for method {method_name}")


def maybe_extract_download_json(job_result: Dict[str, Any], token: str) -> Dict[str, Any]:
    download_url = (
        job_result.get("result", {})
        .get("download", {})
        .get("url")
    )
    if not download_url:
        return job_result
    resp = requests.get(download_url, headers={"Authorization": f"Bearer {token}"}, timeout=60)
    resp.raise_for_status()
    try:
        return resp.json()
    except Exception:
        return {"raw_text": resp.text}


def iter_candidate_pairs(obj: Any, prefix: str = "") -> Iterable[tuple[str, Any]]:
    if isinstance(obj, dict):
        for k, v in obj.items():
            new_prefix = f"{prefix}.{k}" if prefix else k
            yield from iter_candidate_pairs(v, new_prefix)
    elif isinstance(obj, list):
        for i, v in enumerate(obj):
            new_prefix = f"{prefix}[{i}]"
            yield from iter_candidate_pairs(v, new_prefix)
    else:
        yield prefix, obj


def pick_candidate(source_data: Any, candidate_names: list[str]) -> Optional[Any]:
    flattened = list(iter_candidate_pairs(source_data))
    lowered = [(path.lower(), value) for path, value in flattened]
    for name in candidate_names:
        needle = name.lower()
        for path, value in lowered:
            if needle in path:
                return value
    return None


def extract_load_candidates(source_view_payload: Dict[str, Any]) -> Dict[str, Any]:
    """Best-effort candidate extraction.

    TODO: Replace these heuristics with exact field paths after confirming the
    real `view_turbine_data` DataView schema.
    """
    source_blob = source_view_payload.get("result") or source_view_payload
    if "data" in source_blob:
        source_blob = source_blob["data"]

    return {
        "mast_diameter": pick_candidate(source_blob, [
            "mast_diameter", "tower_diameter", "diameter", "foundation_interface_diameter"
        ]),
        "mast_vertical_load": pick_candidate(source_blob, [
            "mast_vertical_load", "vertical_load", "vertical force", "vertical_force", "fz"
        ]),
        "mast_horizontal_load": pick_candidate(source_blob, [
            "mast_horizontal_load", "horizontal_load", "horizontal force", "horizontal_force", "fx"
        ]),
        "mast_moment": pick_candidate(source_blob, [
            "mast_moment", "moment", "overturning_moment", "mx"
        ]),
    }


def build_target_payload(target_saved_or_live: Dict[str, Any], source_candidates: Dict[str, Any]) -> Dict[str, Any]:
    payload = deep_merge(TARGET_BASE_PAYLOAD, target_saved_or_live or {})
    sec_mast = payload.setdefault("step_geo", {}).setdefault("sec_mast", {})

    if source_candidates.get("mast_diameter") is not None:
        sec_mast["mast_diameter"] = source_candidates["mast_diameter"]
    if source_candidates.get("mast_vertical_load") is not None:
        sec_mast["mast_vertical_load"] = source_candidates["mast_vertical_load"]
    if source_candidates.get("mast_horizontal_load") is not None:
        sec_mast["mast_horizontal_load"] = source_candidates["mast_horizontal_load"]
    if source_candidates.get("mast_moment") is not None:
        sec_mast["mast_moment"] = source_candidates["mast_moment"]

    return payload


def log_blocked_requirements(target_payload: Dict[str, Any]) -> None:
    esa_file = (
        target_payload.get("step_analysis", {})
        .get("esa_file")
    )
    if not esa_file:
        print("BLOCKED: missing step_analysis.esa_file (SCIA template .esa upload required)")


def main() -> int:
    token = get_token()

    print("Reading target saved/default values...")
    target_saved = get_entity_properties(token, TARGET_WORKSPACE_ID, TARGET_ENTITY_ID)

    print(f"Running source DataView method: {SOURCE_METHOD}")
    try:
        source_job = run_entity_method(token, SOURCE_WORKSPACE_ID, SOURCE_ENTITY_ID, SOURCE_METHOD)
        source_payload = maybe_extract_download_json(source_job, token)
    except Exception as exc:
        print(f"WARNING: source method execution did not return a proven schema: {exc}")
        source_payload = {}

    candidates = extract_load_candidates(source_payload)
    print("Candidate extracted source fields:")
    print(json.dumps(candidates, indent=2, default=str))

    target_payload = build_target_payload(target_saved, candidates)

    print("Final bridged target payload preview:")
    print(json.dumps(target_payload, indent=2, default=str))

    log_blocked_requirements(target_payload)

    print("INFO: Geometry/geotech defaults/saved values preserved for unmapped fields.")
    print("INFO: TODO remains to prove exact URL 1 DataView schema and tighten field mappings.")
    return 0


if __name__ == "__main__":
    sys.exit(main())
